// Parse IEM CSV and filter for HAIL events >= 0.75 inches
const raw = $input.first().json.data || '';
const lines = raw.split('\n').map(l => l.trim()).filter(l => l.length > 0);

if (lines.length < 2) {
  return [{ json: { hailEvents: [], count: 0 } }];
}

const headers = lines[0].split(',').map(h => h.trim().replace(/^"|"$/g, ''));
const events = [];
const seenCities = new Set();

for (let i = 1; i < lines.length; i++) {
  // Handle CSV with quoted fields
  const values = lines[i].match(/(?:"[^"]*"|[^,]*)(?:,|$)/g)
    ?.map(v => v.replace(/,?$/, '').replace(/^"|"$/g, '').trim()) || lines[i].split(',');

  const row = {};
  headers.forEach((h, idx) => { row[h] = values[idx] || ''; });

  const typetext = (row['typetext'] || row['type'] || '').toUpperCase();
  const magnitude = parseFloat(row['magnitude'] || row['mag'] || '0');
  const city = (row['city'] || '').trim();
  const state = (row['st'] || row['state'] || '').trim().toUpperCase();
  const lat = row['lat'] || '';
  const lon = row['lon'] || '';
  const county = row['county'] || '';
  const timestamp = row['valid'] || row['utc_valid'] || '';

  // Filter: HAIL only, size >= 0.75 inches, valid location
  // Kansas (KS) and Missouri (MO) only
  const targetStates = ['KS', 'MO'];
  if (typetext === 'HAIL' && magnitude >= 0.75 && city && state && targetStates.includes(state)) {
    const cityKey = `${city.toLowerCase()},${state}`;
    // Deduplicate by city+state
    if (!seenCities.has(cityKey)) {
      seenCities.add(cityKey);
      events.push({
        city,
        state,
        county,
        lat,
        lon,
        hailSize: magnitude,
        timestamp,
        cityKey
      });
    }
  }
}

console.log(`Found ${events.length} unique cities with hail >= 0.75"`);

if (events.length === 0) {
  // Return a no-op signal
  return [{ json: { __noHail: true, message: 'No qualifying hail events in last 24 hours.' } }];
}

return events.map(e => ({ json: e }));

// Parse Overpass API response into address objects
const elements = $input.first().json.elements || [];
const hailCity = $('Filter - Skip if No Hail Today').item.json.city || '';
const hailState = $('Filter - Skip if No Hail Today').item.json.state || '';
const hailSize = $('Filter - Skip if No Hail Today').item.json.hailSize || '';
const hailDate = $('Filter - Skip if No Hail Today').item.json.timestamp || '';

const addresses = elements
  .filter(el => el.tags && el.tags['addr:housenumber'] && el.tags['addr:street'])
  .map(el => ({
    street: `${el.tags['addr:housenumber']} ${el.tags['addr:street']}`,
    city: el.tags['addr:city'] || hailCity,
    state: el.tags['addr:state'] || hailState,
    zip: el.tags['addr:postcode'] || '',
    _hailSize: hailSize,
    _hailDate: hailDate
  }))
  .filter(a => a.street && a.city && a.state);

return addresses.map(a => ({ json: a }));

// Build skip trace request from property results
const items = $input.all();
const requests = items.map(item => {
  const prop = item.json;
  const addr = prop.address || prop.propertyAddress || prop.siteAddress || {};
  return {
    propertyAddress: {
      street: addr.street || addr.streetAddress || addr.line1 || prop.streetAddress || '',
      city: addr.city || prop.city || '',
      state: addr.state || prop.state || '',
      zip: addr.zip || addr.postalCode || prop.zip || ''
    }
  };
}).filter(r => r.propertyAddress.street);

return [{ json: { requests } }];

// Extract leads from skip trace results, filter DNC
const output = [];

$input.all().forEach(item => {
  const persons = (item.json.results || item.json.persons || []);
  persons.forEach(person => {
    if (!person || !person.name) return;

    const firstName = person.name?.first || '';
    const lastName = person.name?.last || '';
    if (!firstName && !lastName) return;

    // Get best phone: prefer mobile, non-DNC
    const phones = [
      ...(person.phoneNumbers || person.phones || []),
      ...(person.mobilePhones || [])
    ];
    const cleanPhone = phones.find(p => {
      const status = (p.dnc || p.dncStatus || p.status || '').toLowerCase();
      return status !== 'dnc' && status !== 'do_not_call' && (p.number || p.phone);
    });

    if (!cleanPhone) return; // Skip DNC contacts

    const phoneNumber = cleanPhone.number || cleanPhone.phone || '';
    const email = (person.emails || person.emailAddresses || [])[0]?.email
      || (person.emails || person.emailAddresses || [])[0] || '';

    const propAddr = person.propertyAddress || person.property?.address || {};
    const streetAddress = [
      propAddr.street || propAddr.streetAddress || propAddr.line1 || '',
      propAddr.city || '',
      propAddr.state || ''
    ].filter(Boolean).join(', ');

    output.push({
      json: {
        firstName,
        lastName,
        email: typeof email === 'string' ? email : '',
        phone: phoneNumber,
        company: streetAddress,
        source: 'hail_lead_gen',
        systemInterest: 'hot_lead',
        notes: `Hail storm lead. Property: ${streetAddress}. Hail size: ${person._hailSize || ''}" Storm date: ${person._stormDate || new Date().toISOString().split('T')[0]}.`,
        _city: propAddr.city || '',
        _state: propAddr.state || ''
      }
    });
  });
});

console.log(`Formatted ${output.length} DNC-clean leads`);
return output;

// Aggregate summary stats for internal email
const leads = $input.all();
const total = leads.length;
const cities = [...new Set(leads.map(l => l.json._city).filter(Boolean))];
const states = [...new Set(leads.map(l => l.json._state).filter(Boolean))];
const date = new Date().toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });

return [{
  json: {
    totalLeads: total,
    citiesHit: cities.join(', ') || 'Various',
    statesHit: states.join(', ') || 'Various',
    date
  }
}];
